val listState = rememberLazyListState()
val shouldLoadMore by remember {
    derivedStateOf {
        val lastVisible = listState.layoutInfo.visibleItemsInfo.lastOrNull()?.index ?: 0
        lastVisible >= totalItems - LOAD_THRESHOLD
    }
}
LaunchedEffect(shouldLoadMore) {
    if (shouldLoadMore && !isLoading) onLoadMore()
}
LazyColumn(state = listState) {
    items(items = list, key = { it.id }) { item ->
        ItemRow(item)
    }
    if (isLoading) item { CircularProgressIndicator() }
}

val devicePosture by rememberDevicePosture()
when (devicePosture) {
    is TableTopPosture -> TableTopLayout(foldingFeature = (devicePosture as TableTopPosture).hingePosition)
    is BookPosture    -> BookLayout()
    else              -> StandardLayout()
}

